def fizz_buzz(n: int):
    """Return the number of times the digit 7 appears in integers less than n which are divisible by 11 or 13.
    >>> fizz_buzz(50)
    0
    >>> fizz_buzz(78)
    2
    >>> fizz_buzz(79)
    3
    """
    return sum(
        len([digit for digit in str(i) if digit == "7"]) for i in range(1, n, 11)
    ) + sum(
        len([digit for digit in str(i) if digit == "7"]) for i in range(1, n, 13)
    )

