def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    if number > 1000 or number < 1:
        raise ValueError("Number has to be between 1 and 1000!")
    else:
        roman_dict = {1000:'M', 900:'CM', 500:'D', 400:'CD', 100:'C', 90:'XC', 50:'L', 40:'XL', 10:'X', 9:'IX', 5:'V', 4:'IV', 1:'I'}
        roman_numerals = []
        for n, i in roman_dict.items():
            while number >= n:
                roman_numerals.append(i)
                number -= n
        return ''.join(roman_numerals)

def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    if number > 1000:
        raise ValueError("Number has to be less than 1000!")
    else:
        roman = []
        while number >= 100:
            number -= 100
            roman.append('c')
        while number >= 50:
            number -= 50
            roman.append('l')
        while number >= 10:
            number -= 10
            roman.append('x')
        while number >= 5:
            number -= 5
            roman.append('v')
        while number >= 1:
            number -= 1
            roman.append('i')
        return ''.join(roman)
